const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

// Rounding policies — both round in MHPCO's favor
const roundPremiumInMHPCOFavor = Math.ceil;
const roundPayoutInMHPCOFavor = Math.floor;
